export enum ExpenseType {
  NEED = 'احتياج',
  WANT = 'رغبة',
  SAVING = 'ادخار واستثمار'
}

export enum AppStep {
  SALARY = 1,
  EXPENSES = 2,
  DASHBOARD = 3
}

export type Language = 'ar' | 'en';

export interface Expense {
  id: string;
  name: string;
  amount: number;
  type: ExpenseType;
  notes?: string;
}

export interface Suggestion {
  name: string;
}

export interface DashboardMetrics {
  totalNeeds: number;
  totalWants: number;
  totalSavingsExpenses: number; // Savings explicitly listed as expenses
  totalExpenses: number;
  remainingSalary: number;
  totalSavingsCalculated: number; // (Salary - Needs - Wants)
}

import React from 'react';
import { DashboardMetrics, AppStep, Language } from '../types';
import { RotateCcw, Users, Globe } from 'lucide-react';
import { TRANSLATIONS } from '../constants';

interface StickyHeaderProps {
  salary: number;
  metrics: DashboardMetrics;
  onReset: () => void;
  currentStep: AppStep;
  visitorCount: number;
  lang: Language;
  setLang: (l: Language) => void;
}

export const StickyHeader: React.FC<StickyHeaderProps> = ({ 
  salary, 
  metrics, 
  onReset, 
  currentStep,
  visitorCount,
  lang,
  setLang
}) => {
  const t = TRANSLATIONS[lang];
  const savingsPercentage = salary > 0 ? Math.round((metrics.totalSavingsCalculated / salary) * 100) : 0;

  const steps = [
    { id: AppStep.SALARY, label: t.step1 },
    { id: AppStep.EXPENSES, label: t.step2 },
    { id: AppStep.DASHBOARD, label: t.step3 },
  ];

  return (
    <div className="sticky-header bg-white/95 border-b border-gray-200 shadow-sm pt-2 pb-3 px-4 mb-6 backdrop-blur-md transition-all duration-300">
      <div className="max-w-4xl mx-auto">

        {/* Top Bar: Language | Visitor | Reset */}
        <div className="flex justify-between items-center mb-3">
            <div className="flex items-center gap-2">
                <button 
                    onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')}
                    className="flex items-center gap-1 bg-gray-100 hover:bg-gray-200 px-3 py-1 rounded-full text-xs font-bold text-gray-600 transition-colors"
                >
                    <Globe size={12} />
                    {lang === 'ar' ? 'English' : 'العربية'}
                </button>
                <div className="hidden sm:flex items-center gap-1 bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-xs font-bold">
                    <Users size={12} />
                    <span>{visitorCount.toLocaleString()} {t.visitors}</span>
                </div>
            </div>

            <div className="flex items-center gap-3">
                 <button 
                   onClick={onReset}
                   className="flex items-center gap-1 text-red-400 hover:text-red-600 hover:bg-red-50 px-2 py-1 rounded transition-all group"
                   title={t.reset}
                   data-html2canvas-ignore
                 >
                   <RotateCcw size={14} className="group-hover:-rotate-180 transition-transform duration-500" />
                   <span className="text-xs hidden sm:inline">{t.reset}</span>
                 </button>
            </div>
        </div>

        {/* Logo & Steps */}
        <div className="flex flex-col md:flex-row items-center justify-between gap-4">

            {/* Logo */}
            <div className="flex items-center gap-2">
                 <img src="./QAWAM_logo.png" alt="QAWAM" className="h-8 md:h-10 object-contain" />
            </div>

            {/* Step Progress */}
            <div className="flex items-center w-full md:w-auto justify-center">
                {steps.map((step, idx) => (
                    <React.Fragment key={step.id}>
                        <div className={`flex flex-col items-center relative z-10 ${currentStep >= step.id ? 'text-blue-600' : 'text-gray-300'}`}>
                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold border-2 transition-all duration-500 ${
                                currentStep >= step.id 
                                ? 'bg-blue-600 text-white border-blue-600' 
                                : 'bg-white text-gray-400 border-gray-200'
                            }`}>
                                {step.id}
                            </div>
                            <span className="text-[10px] font-bold mt-1">{step.label}</span>
                        </div>
                        {idx < steps.length - 1 && (
                            <div className={`h-0.5 w-12 md:w-20 -mt-4 transition-colors duration-500 ${currentStep > step.id ? 'bg-blue-600' : 'bg-gray-200'}`}></div>
                        )}
                    </React.Fragment>
                ))}
            </div>

            {/* Mini Metrics (Only on Dashboard) */}
            <div className={`hidden md:flex items-center gap-3 transition-opacity duration-300 ${currentStep === AppStep.DASHBOARD ? 'opacity-100' : 'opacity-0'}`}>
                 <div className="text-center">
                    <div className="text-[10px] text-gray-500">{t.remaining}</div>
                    <div className={`font-bold text-sm ${metrics.remainingSalary < 0 ? 'text-red-600' : 'text-blue-600'}`}>
                        {metrics.remainingSalary.toLocaleString()}
                    </div>
                 </div>
                 <div className="w-px h-6 bg-gray-200"></div>
                 <div className="text-center">
                    <div className="text-[10px] text-gray-500">{t.savingsRate}</div>
                    <div className="font-bold text-sm text-emerald-600">%{savingsPercentage}</div>
                 </div>
            </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Expense, ExpenseType, Language } from '../types';
import { EXPENSE_TYPES, SUGGESTED_EXPENSES, EXPENSE_MAPPING, TRANSLATIONS } from '../constants';
import { PlusCircle, Save, X, AlertTriangle } from 'lucide-react';

interface AddExpenseFormProps {
  salary: number;
  currentTotal: number;
  expenses: Expense[];
  onAdd: (expense: Omit<Expense, 'id'>) => boolean; 
  editingExpense?: Expense | null;
  onUpdate: (updatedExpense: Expense) => boolean;
  onCancelEdit: () => void;
  lang: Language;
}

export const AddExpenseForm: React.FC<AddExpenseFormProps> = ({ 
  salary, 
  currentTotal, 
  expenses,
  onAdd, 
  editingExpense,
  onUpdate,
  onCancelEdit,
  lang
}) => {
  const t = TRANSLATIONS[lang];
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [type, setType] = useState<ExpenseType>(ExpenseType.NEED);
  const [notes, setNotes] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [advice, setAdvice] = useState<string | null>(null);

  useEffect(() => {
    if (editingExpense) {
      setName(editingExpense.name);
      setAmount(editingExpense.amount.toString());
      setType(editingExpense.type);
      setNotes(editingExpense.notes || '');
      setError(null);
      setAdvice(null);
    }
  }, [editingExpense]);

  useEffect(() => {
    if (name && EXPENSE_MAPPING[name]) {
       setType(EXPENSE_MAPPING[name]);
    }
  }, [name]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numAmount = parseFloat(amount);
    if (!name || isNaN(numAmount) || numAmount <= 0) return;

    const amountDiff = editingExpense ? numAmount - editingExpense.amount : numAmount;
    if (currentTotal + amountDiff > salary) {
      const deficit = (currentTotal + amountDiff) - salary;
      setError(`${t.errorSalaryExceeded} (${deficit.toLocaleString()})`);

      const otherExpenses = expenses.filter(e => editingExpense ? e.id !== editingExpense.id : true);
      const currentWants = otherExpenses.filter(e => e.type === ExpenseType.WANT).reduce((sum, e) => sum + e.amount, 0);
      const wantsPct = (currentWants / salary) * 100;

      const largestWant = otherExpenses
        .filter(e => e.type === ExpenseType.WANT)
        .sort((a, b) => b.amount - a.amount)[0];

      let generatedAdvice = "";

      if (lang === 'ar') {
        if (wantsPct > 30 && largestWant) {
            generatedAdvice = `توصية الخبير: إنفاقك على "الرغبات" مرتفع (${Math.round(wantsPct)}%). جرب تقليل بند "${largestWant.name}".`;
        } else if (largestWant) {
            generatedAdvice = `توصية الخبير: حاول تقليل الكماليات مثل "${largestWant.name}".`;
        } else {
            generatedAdvice = `توصية الخبير: ميزانيتك مضغوطة. راجع مصروفاتك.`;
        }
      } else {
        if (wantsPct > 30 && largestWant) {
            generatedAdvice = `Expert Tip: Your 'Wants' are high (${Math.round(wantsPct)}%). Try reducing "${largestWant.name}".`;
        } else if (largestWant) {
            generatedAdvice = `Expert Tip: Try reducing luxuries like "${largestWant.name}".`;
        } else {
            generatedAdvice = `Expert Tip: Your budget is tight. Review your needs.`;
        }
      }

      setAdvice(generatedAdvice);
      return;
    }

    let success = false;
    if (editingExpense) {
      success = onUpdate({ ...editingExpense, name, amount: numAmount, type, notes });
    } else {
      success = onAdd({ name, amount: numAmount, type, notes });
    }

    if (success) {
      if (!editingExpense) {
        setName('');
        setAmount('');
        setNotes('');
        setType(ExpenseType.NEED);
      }
      setError(null);
      setAdvice(null);
    }
  };

  const handleSuggestionSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (e.target.value) {
      setName(e.target.value);
    }
  };

  const getTypeColorClass = (t: ExpenseType) => {
     switch (t) {
       case ExpenseType.NEED: return 'text-red-700 font-bold';
       case ExpenseType.WANT: return 'text-amber-600 font-bold';
       case ExpenseType.SAVING: return 'text-emerald-600 font-bold';
       default: return 'text-gray-700';
     }
  };

  const isRtl = lang === 'ar';

  return (
    <div className="bg-white p-6 rounded-xl shadow-lg w-full max-w-2xl" dir={isRtl ? 'rtl' : 'ltr'}>
      <div className="flex justify-between items-center mb-6 pb-2 border-b border-gray-100">
        <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
          {editingExpense ? <Edit2Icon /> : <PlusCircleIcon />}
          {editingExpense ? (lang === 'ar' ? 'تعديل المصروف' : 'Edit Expense') : t.addExpense}
        </h3>
        <button 
          onClick={onCancelEdit}
          className="text-gray-400 hover:text-gray-600 p-1 rounded-full hover:bg-gray-100 transition-colors"
        >
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">

          <div className="flex flex-col gap-2">
            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseName}</label>

              {lang === 'ar' && (
                  <select 
                    onChange={handleSuggestionSelect}
                    className="w-full mb-2 px-2 py-1.5 text-xs border border-gray-200 bg-gray-50 rounded text-gray-600 focus:border-blue-500 outline-none cursor-pointer"
                    defaultValue=""
                  >
                    <option value="" disabled>↓ اختر من القائمة المقترحة</option>
                    {SUGGESTED_EXPENSES.map((s, i) => (
                      <option key={i} value={s}>{s}</option>
                    ))}
                  </select>
              )}

              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder={lang === 'ar' ? "أو اكتب الاسم هنا..." : "Expense name..."}
                required
                autoFocus={!editingExpense}
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseAmount}</label>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className={`w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all ${lang==='ar' ? 'mt-[29px]' : ''}`}
              placeholder="0.00"
              min="0"
              required
            />
          </div>

          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseType}</label>
            <select
              value={type}
              onChange={(e) => setType(e.target.value as ExpenseType)}
              className={`w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none bg-white md:mt-[29px] ${getTypeColorClass(type)}`}
            >
              {EXPENSE_TYPES.map(t => (
                <option key={t} value={t} className={getTypeColorClass(t)}>{t}</option>
              ))}
            </select>
          </div>

          <div>
             <label className="block text-xs font-semibold text-gray-500 mb-1">{t.notes}</label>
            <input
              type="text"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all md:mt-[29px]"
              placeholder={lang === 'ar' ? "اختياري" : "Optional"}
            />
          </div>
        </div>

        {error && (
          <div className="bg-red-50 border-r-4 border-red-500 p-4 rounded-md animate-pulse">
            <div className="flex items-start">
              <AlertTriangle className="text-red-500 ltr:mr-2 rtl:ml-2 mt-0.5" size={18} />
              <div>
                <p className="text-sm font-bold text-red-700">{error}</p>
                {advice && <p className="text-sm text-red-600 mt-1 bg-white/50 p-2 rounded">{advice}</p>}
              </div>
            </div>
          </div>
        )}

        <div className="flex justify-end gap-3 pt-4 border-t border-gray-100">
            <button
              type="button"
              onClick={onCancelEdit}
              className="px-6 py-2 rounded-lg border border-gray-300 text-gray-600 hover:bg-gray-50 transition-colors flex items-center gap-2"
            >
              {t.cancel}
            </button>
          <button
            type="submit"
            className="px-6 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700 shadow-md transition-colors flex items-center gap-2"
          >
            {editingExpense ? <Save size={18} /> : <PlusCircle size={18} />}
            {editingExpense ? t.save : t.addExpense}
          </button>
        </div>
      </form>
    </div>
  );
};

const Edit2Icon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;
const PlusCircleIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="16"></line><line x1="8" y1="12" x2="16" y2="12"></line></svg>;

import React from 'react';
import { Trash2, Edit2 } from 'lucide-react';
import { Expense, ExpenseType, Language } from '../types';
import { TRANSLATIONS } from '../constants';

interface ExpenseTableProps {
  expenses: Expense[];
  salary: number;
  onDelete: (id: string) => void;
  onEdit: (expense: Expense) => void;
  lang: Language;
}

export const ExpenseTable: React.FC<ExpenseTableProps> = ({ expenses, salary, onDelete, onEdit, lang }) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  const getPercentageColor = (amount: number): string => {
    if (salary === 0) return 'bg-gray-100 text-gray-500';
    const percentage = (amount / salary) * 100;
    if (percentage <= 5) return 'bg-green-100 text-green-800';
    if (percentage <= 15) return 'bg-amber-100 text-amber-800';
    return 'bg-red-100 text-red-800';
  };

  const getTypeBadge = (type: ExpenseType) => {
    switch (type) {
      case ExpenseType.NEED: return <span className="px-2 py-1 rounded-full text-xs bg-red-100 text-red-800 font-medium">{type}</span>;
      case ExpenseType.WANT: return <span className="px-2 py-1 rounded-full text-xs bg-amber-100 text-amber-800 font-medium">{type}</span>;
      case ExpenseType.SAVING: return <span className="px-2 py-1 rounded-full text-xs bg-emerald-100 text-emerald-800 font-medium">{type}</span>;
    }
  };

  return (
    <div className="overflow-x-auto rounded-lg border border-gray-200" dir={isRtl ? 'rtl' : 'ltr'}>
      <table className="w-full text-sm text-right">
        <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
          <tr>
            <th className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{t.expenseName}</th>
            <th className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{t.expenseType}</th>
            <th className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{t.expenseAmount}</th>
            <th className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{t.expenseAmount} %</th>
            <th className={`px-4 py-3 hidden md:table-cell ${isRtl ? 'text-right' : 'text-left'}`}>{t.notes}</th>
            <th className="px-4 py-3 text-center w-24"></th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100 bg-white">
          {expenses.length === 0 ? (
            <tr>
              <td colSpan={6} className="px-4 py-8 text-center text-gray-400">
                {t.noExpenses}
              </td>
            </tr>
          ) : (
            expenses.map((expense) => {
              const percentage = salary > 0 ? Math.ceil((expense.amount / salary) * 100) : 0;
              return (
                <tr key={expense.id} className="hover:bg-gray-50 transition-colors">
                  <td className={`px-4 py-3 font-medium text-gray-900 ${isRtl ? 'text-right' : 'text-left'}`}>{expense.name}</td>
                  <td className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{getTypeBadge(expense.type)}</td>
                  <td className={`px-4 py-3 font-semibold ${isRtl ? 'text-right' : 'text-left'}`}>{expense.amount.toLocaleString()}</td>
                  <td className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>
                    <span className={`inline-block px-2 py-1 rounded text-xs font-bold ${getPercentageColor(expense.amount)}`}>
                      %{percentage}
                    </span>
                  </td>
                  <td className={`px-4 py-3 text-gray-500 max-w-xs truncate hidden md:table-cell ${isRtl ? 'text-right' : 'text-left'}`}>{expense.notes || '-'}</td>
                  <td className="px-4 py-3">
                    {/* Mobile Optimized Actions: Stacked or Larger touch targets */}
                    <div className="flex items-center justify-center gap-3 md:gap-2">
                      <button 
                        onClick={() => onEdit(expense)} 
                        className="p-2 md:p-1.5 bg-blue-50 text-blue-600 hover:bg-blue-100 rounded-lg transition-colors shadow-sm"
                        title={t.edit}
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => onDelete(expense.id)} 
                        className="p-2 md:p-1.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg transition-colors shadow-sm"
                        title={t.delete}
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })
          )}
        </tbody>
      </table>
    </div>
  );
};

import React from 'react';
import { DashboardMetrics, Expense, ExpenseType, Language } from '../types';
import { PieChart, Pie, Cell, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import { COLORS, TRANSLATIONS } from '../constants';

interface PrintableReportProps {
  salary: number;
  metrics: DashboardMetrics;
  expenses: Expense[];
  lang: Language;
}

export const PrintableReport: React.FC<PrintableReportProps> = ({ salary, metrics, expenses, lang }) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  // Pie Chart Data
  const pieData = [
    { name: ExpenseType.NEED, value: metrics.totalNeeds, color: COLORS[ExpenseType.NEED] },
    { name: ExpenseType.WANT, value: metrics.totalWants, color: COLORS[ExpenseType.WANT] },
    { name: ExpenseType.SAVING, value: metrics.totalSavingsCalculated, color: COLORS[ExpenseType.SAVING] },
  ].filter(item => item.value > 0);

  // Bar Chart Data
  const getPercent = (val: number) => salary > 0 ? parseFloat(((val / salary) * 100).toFixed(1)) : 0;
  const barData = [
    { name: ExpenseType.NEED, actual: getPercent(metrics.totalNeeds), target: 50, color: COLORS[ExpenseType.NEED] },
    { name: ExpenseType.WANT, actual: getPercent(metrics.totalWants), target: 30, color: COLORS[ExpenseType.WANT] },
    { name: ExpenseType.SAVING, actual: getPercent(metrics.totalSavingsCalculated), target: 20, color: COLORS[ExpenseType.SAVING] },
  ];

  const today = new Date().toLocaleDateString(lang === 'ar' ? 'ar-SA' : 'en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });

  return (
    <div 
      id="printable-report" 
      className="bg-white p-8 mx-auto flex flex-col"
      style={{ 
        width: '794px', // A4 Width
        minHeight: '1123px', // A4 Height
        direction: isRtl ? 'rtl' : 'ltr',
        fontFamily: 'Calibri, sans-serif'
      }}
    >
      {/* --- HEADER SECTION --- */}
      <div className="border-b border-gray-200 pb-4 mb-6">
        <div className="flex justify-between items-center mb-4 px-1 gap-2">
          <div className="text-xs text-gray-500 w-32">{today}</div>
          <div className="flex-1 text-center mx-2">
             <span className="font-diwani text-emerald-700 text-xl block leading-tight mb-1">
               {isRtl ? '﴿وَالَّذِينَ إِذَا أَنفَقُوا لَمْ يُسْرِفُوا وَلَمْ يَقْتُرُوا وَكَانَ بَيْنَ ذَٰلِكَ قَوَامًا﴾' : 'QAWAM Financial Report'}
             </span>
          </div>
          <div className="w-32 flex justify-end">
             <span className="text-xs text-gray-400 font-mono bg-gray-100 px-2 py-1 rounded-full">v1.4</span>
          </div>
        </div>
        <div className="flex flex-col items-center gap-2">
          <div className="flex justify-center w-full">
            <img src="./QAWAM_logo.png" alt="QAWAM" className="h-16 object-contain" />
          </div>
          <h2 className="text-lg font-bold text-gray-800 border-b-2 border-emerald-500 pb-1 px-4">
              {lang === 'ar' ? 'تقرير مالي شامل' : 'Comprehensive Financial Report'}
          </h2>
        </div>
      </div>

      {/* --- CONTENT SECTION --- */}
      <div className="mb-8">
        <h3 className="text-sm font-bold text-gray-500 mb-3">{t.step3}</h3>
        <div className="grid grid-cols-4 gap-4">
          <div className="bg-gray-50 p-4 border border-gray-200 rounded-lg text-center">
            <span className="block text-gray-500 text-xs mb-1">{t.salaryLabel}</span>
            <span className="block text-xl font-black text-gray-800">{salary.toLocaleString()}</span>
            <span className="text-[10px] text-gray-400">{t.currency}</span>
          </div>
          <div className="bg-gray-50 p-4 border border-gray-200 rounded-lg text-center">
            <span className="block text-gray-500 text-xs mb-1">{t.totalExpenses}</span>
            <span className="block text-xl font-black text-gray-700">{metrics.totalExpenses.toLocaleString()}</span>
            <span className="text-[10px] text-gray-400">{t.currency}</span>
          </div>
          <div className="bg-blue-50 p-4 border border-blue-100 rounded-lg text-center">
            <span className="block text-blue-600 text-xs mb-1">{t.remaining}</span>
            <span className="block text-xl font-black text-blue-700">{metrics.remainingSalary.toLocaleString()}</span>
            <span className="text-[10px] text-blue-400">{t.currency}</span>
          </div>
          <div className="bg-emerald-50 p-4 border border-emerald-100 rounded-lg text-center">
            <span className="block text-emerald-600 text-xs mb-1">{t.savingsRate}</span>
            <span className="block text-xl font-black text-emerald-700">
              {salary > 0 ? Math.round((metrics.totalSavingsCalculated / salary) * 100) : 0}%
            </span>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="mb-8 bg-gray-50 border border-gray-100 rounded-xl p-6">
        <div className="flex justify-between items-start gap-4">

          {/* Pie Chart - Fixed Legend Issue */}
          <div style={{ width: 330, height: 220, direction: 'ltr' }} className="flex flex-col items-center">
            <PieChart width={330} height={200}>
              <Pie
                data={pieData}
                cx="50%"
                cy="50%"
                innerRadius={50}
                outerRadius={70}
                paddingAngle={2}
                dataKey="value"
                isAnimationActive={false}
              >
                {pieData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} strokeWidth={1} stroke="#fff" />
                ))}
              </Pie>
              {/* Legend handles values to avoid text clipping on PDF */}
              <Legend 
                verticalAlign="middle" 
                align="right"
                layout="vertical"
                formatter={(value, entry: any) => {
                    const val = entry.payload.value;
                    const pct = ((val/salary)*100).toFixed(0);
                    return <span style={{ color: '#333', fontSize: '10px', fontWeight: 'bold' }}>{value} ({pct}%)</span>
                }}
              />
            </PieChart>
          </div>

          <div className="w-px h-40 bg-gray-200 mt-4"></div>

          {/* Bar Chart */}
          <div style={{ width: 330, height: 220, direction: 'ltr' }} className="flex flex-col items-center">
            <BarChart
              width={330}
              height={200}
              data={barData}
              margin={{ top: 5, right: 10, left: -20, bottom: 5 }}
            >
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="name" tick={{ fontSize: 10, fontFamily: 'Calibri' }} interval={0} />
              <YAxis tick={{ fontSize: 10 }} unit="%" />
              <Legend 
                verticalAlign="top" 
                height={36} 
                formatter={(val) => val === 'target' ? t.target : t.actual}
                wrapperStyle={{ fontSize: '10px' }}
              />
              <Bar dataKey="target" fill={COLORS.target} barSize={25} isAnimationActive={false} radius={[4, 4, 0, 0]} />
              <Bar dataKey="actual" barSize={25} isAnimationActive={false} radius={[4, 4, 0, 0]}>
                {barData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </div>

        </div>
      </div>

      {/* Detailed Table */}
      <div className="mb-8 flex-1">
        <h3 className="text-sm font-bold text-gray-600 mb-3 border-r-4 border-gray-400 pr-2 rtl:border-r-4 rtl:border-l-0 ltr:border-l-4 ltr:border-r-0">
            {t.expensesTitle}
        </h3>
        <table className={`w-full text-sm ${isRtl ? 'text-right' : 'text-left'}`}>
          <thead>
            <tr className="bg-gray-100 text-gray-700">
              <th className="p-2 border border-gray-200 text-xs">{t.expenseName}</th>
              <th className="p-2 border border-gray-200 text-xs w-24">{t.expenseType}</th>
              <th className="p-2 border border-gray-200 text-xs w-24">{t.expenseAmount}</th>
              <th className="p-2 border border-gray-200 text-xs w-16">%</th>
              <th className="p-2 border border-gray-200 text-xs">{t.notes}</th>
            </tr>
          </thead>
          <tbody>
            {expenses.map((expense, idx) => (
              <tr key={expense.id} className={idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}>
                <td className="p-2 border border-gray-200 font-bold text-gray-800">{expense.name}</td>
                <td className="p-2 border border-gray-200 text-gray-600 text-xs">{expense.type}</td>
                <td className="p-2 border border-gray-200 font-mono text-gray-700">{expense.amount.toLocaleString()}</td>
                <td className="p-2 border border-gray-200 text-xs text-gray-500">
                  {salary > 0 ? ((expense.amount / salary) * 100).toFixed(1) : 0}%
                </td>
                <td className="p-2 border border-gray-200 text-gray-400 text-xs">{expense.notes || '-'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="mt-auto pt-6 border-t border-gray-200 text-center">
        <p className="text-[10px] text-gray-400 opacity-70">© {new Date().getFullYear()} {t.appTitle}</p>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { StickyHeader } from './components/StickyHeader';
import { FinancialChart } from './components/FinancialChart';
import { TargetVsActualChart } from './components/TargetVsActualChart';
import { ExpenseTable } from './components/ExpenseTable';
import { AddExpenseForm } from './components/AddExpenseForm';
import { PrintableReport } from './components/PrintableReport';
import { Expense, ExpenseType, DashboardMetrics, AppStep, Language } from './types';
import { TRANSLATIONS } from './constants';
import { Download, Info, AlertCircle, CheckCircle2, Plus, ArrowRight, ArrowLeft, Send } from 'lucide-react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

// Helper for Analysis Cards
function AnalysisCard({ title, current, target, color, isMinimum = false, lang }: any) {
  const t = TRANSLATIONS[lang as Language];
  const diff = current - target;
  const isNegative = isMinimum ? diff < -5 : diff > 5; 

  const colors: Record<string, string> = {
    blue: 'bg-blue-50 text-blue-700 border-blue-100',
    red: 'bg-red-50 text-red-700 border-red-100',
    amber: 'bg-amber-50 text-amber-700 border-amber-100',
    emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
  };

  return (
    <div className={`p-4 rounded-lg border ${colors[color]} transition-all hover:shadow-sm`}>
      <div className="flex justify-between items-start mb-2">
        <span className="text-sm font-bold">{title}</span>
        <span className="text-xs bg-white px-2 py-0.5 rounded shadow-sm opacity-80 font-mono font-bold">{Math.round(current)}%</span>
      </div>
      <div className="w-full bg-white/50 h-2 rounded-full mb-2 overflow-hidden">
        <div 
          className={`h-full rounded-full transition-all duration-1000 ease-out bg-current`} 
          style={{ width: `${Math.min(current, 100)}%` }}
        ></div>
      </div>
      {isNegative ? (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <AlertCircle size={12} className="mt-0.5 shrink-0" />
          <span>
             {isMinimum 
               ? `${t.belowTarget} ${Math.abs(Math.round(diff))}%` 
               : `${t.aboveTarget} ${Math.round(diff)}%`}
          </span>
        </div>
      ) : (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <CheckCircle2 size={12} className="mt-0.5 shrink-0" />
          <span>{t.idealRange}</span>
        </div>
      )}
    </div>
  );
}

function App() {
  const [lang, setLang] = useState<Language>('ar');
  const [step, setStep] = useState<AppStep>(AppStep.SALARY);
  const [salary, setSalary] = useState<number>(0);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [visitorCount, setVisitorCount] = useState<number>(12050);

  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  // Initialize from LocalStorage
  useEffect(() => {
    const savedExpenses = localStorage.getItem('qawam_expenses');
    const savedSalary = localStorage.getItem('qawam_salary');
    const savedVisitor = localStorage.getItem('qawam_visitors');

    // Simple mock visitor logic
    let count = 12050;
    if (savedVisitor) {
       count = parseInt(savedVisitor);
    } else {
       count = 12050 + Math.floor(Math.random() * 50);
       localStorage.setItem('qawam_visitors', count.toString());
    }
    setVisitorCount(count);

    if (savedSalary) {
      const s = parseFloat(savedSalary);
      setSalary(s);
      if (s > 0) {
          // If expenses exist, go to dashboard, else salary/expenses
          if(savedExpenses && JSON.parse(savedExpenses).length > 0) {
              setStep(AppStep.DASHBOARD);
          } else {
              setStep(AppStep.EXPENSES);
          }
      }
    }

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    }
  }, []);

  // Save on Change
  useEffect(() => {
    localStorage.setItem('qawam_expenses', JSON.stringify(expenses));
    localStorage.setItem('qawam_salary', salary.toString());
  }, [expenses, salary]);

  // Calculations
  const metrics: DashboardMetrics = React.useMemo(() => {
    const totalNeeds = expenses.filter(e => e.type === ExpenseType.NEED).reduce((acc, curr) => acc + curr.amount, 0);
    const totalWants = expenses.filter(e => e.type === ExpenseType.WANT).reduce((acc, curr) => acc + curr.amount, 0);
    const totalSavingsExpenses = expenses.filter(e => e.type === ExpenseType.SAVING).reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpenses = totalNeeds + totalWants + totalSavingsExpenses;
    const remainingSalary = salary - totalExpenses;
    const totalSavingsCalculated = Math.max(0, salary - totalNeeds - totalWants);

    return {
      totalNeeds,
      totalWants,
      totalSavingsExpenses,
      totalExpenses,
      remainingSalary,
      totalSavingsCalculated
    };
  }, [expenses, salary]);

  // Handlers
  const handleNextStep = () => {
      if (step === AppStep.SALARY && salary > 0) setStep(AppStep.EXPENSES);
      else if (step === AppStep.EXPENSES) setStep(AppStep.DASHBOARD);
  };

  const handlePrevStep = () => {
      if (step === AppStep.EXPENSES) setStep(AppStep.SALARY);
      else if (step === AppStep.DASHBOARD) setStep(AppStep.EXPENSES);
  };

  const handleOpenAddModal = () => {
    setEditingExpense(null);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (expense: Expense) => {
    setEditingExpense(expense);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setTimeout(() => setEditingExpense(null), 300);
  };

  const handleAddExpense = (newExpenseData: Omit<Expense, 'id'>) => {
    const newExpense = { ...newExpenseData, id: Date.now().toString() };
    setExpenses(prev => [newExpense, ...prev]);
    handleCloseModal();
    return true;
  };

  const handleUpdateExpense = (updatedExpense: Expense) => {
    setExpenses(prev => prev.map(e => e.id === updatedExpense.id ? updatedExpense : e));
    handleCloseModal();
    return true;
  };

  const handleDeleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const handleReset = () => {
    if (window.confirm(lang === 'ar' ? 'هل أنت متأكد من حذف البيانات؟' : 'Are you sure you want to reset data?')) {
      localStorage.removeItem('qawam_expenses');
      localStorage.removeItem('qawam_salary');
      setSalary(0);
      setExpenses([]);
      setEditingExpense(null);
      setStep(AppStep.SALARY);
      window.scrollTo(0, 0);
    }
  };

  const exportPDF = async () => {
    setIsExporting(true);
    try {
      const input = document.getElementById('printable-report');
      if (!input) throw new Error('Report not found');

      // Temporarily show report to capture
      input.style.display = 'flex';

      const canvas = await html2canvas(input, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });

      // Hide again (actually it's fixed offscreen in JSX)

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF(isRtl ? 'p' : 'p', 'mm', 'a4'); // No RTL config needed for images

      const imgWidth = 210; 
      const pageHeight = 297; 
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;

      while (heightLeft > 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`QAWAM-Report-${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (err) {
      console.error(err);
      alert(lang === 'ar' ? "خطأ في التصدير" : "Export Error");
    } finally {
      setIsExporting(false);
    }
  };

  const getAnalysis = () => {
    if (salary === 0) return null;
    const needPct = (metrics.totalNeeds / salary) * 100;
    const wantPct = (metrics.totalWants / salary) * 100;
    const savePct = (metrics.totalSavingsCalculated / salary) * 100;

    const isBalanced = 
      Math.abs(needPct - 50) <= 5 && 
      Math.abs(wantPct - 30) <= 5 && 
      savePct >= 15;

    return (
      <div className="mb-6">
        {isBalanced && (
          <div className="mb-4 bg-emerald-50 border border-emerald-200 rounded-xl p-3 flex items-center gap-3 animate-pulse">
            <div className="bg-emerald-100 p-2 rounded-full text-emerald-600">
              <CheckCircle2 size={24} />
            </div>
            <div>
              <p className="font-bold text-emerald-800">{t.balancedMessage}</p>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <AnalysisCard title={`${t.needs} (${t.target} 50%)`} current={needPct} target={50} color="red" lang={lang} />
          <AnalysisCard title={`${t.wants} (${t.target} 30%)`} current={wantPct} target={30} color="amber" lang={lang} />
          <AnalysisCard title={`${t.savings} (${t.target} 20%)`} current={savePct} target={20} color="emerald" isMinimum lang={lang} />
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-24 relative flex flex-col" dir={isRtl ? 'rtl' : 'ltr'}>
      <StickyHeader 
        salary={salary} 
        metrics={metrics} 
        onReset={handleReset} 
        currentStep={step} 
        visitorCount={visitorCount}
        lang={lang}
        setLang={setLang}
      />

      {/* Hidden Report for PDF */}
      <div style={{ position: 'fixed', left: '-10000px', top: 0, zIndex: -5, overflow: 'hidden' }}>
        <PrintableReport salary={salary} metrics={metrics} expenses={expenses} lang={lang} />
      </div>

      <main className="max-w-4xl mx-auto px-4 flex-grow w-full">

        {/* --- STEP 1: SALARY --- */}
        {step === AppStep.SALARY && (
            <div className="animate-fade-in flex flex-col items-center justify-center min-h-[50vh]">
                 <div className="bg-white rounded-2xl shadow-xl border border-blue-100 p-8 w-full max-w-lg text-center relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-500 to-emerald-500"></div>

                    <h2 className="text-2xl font-bold text-gray-800 mb-6">{t.salaryLabel}</h2>

                    <div className="relative mb-6">
                        <input
                        type="number"
                        value={salary || ''}
                        onChange={(e) => setSalary(parseFloat(e.target.value))}
                        placeholder="0"
                        autoFocus
                        className="w-full font-black text-gray-800 border-b-2 border-gray-200 focus:border-blue-600 outline-none bg-transparent transition-all placeholder-gray-200 text-5xl text-center py-4"
                        />
                        <span className={`absolute text-gray-400 font-medium bottom-6 text-lg ${isRtl ? 'left-4' : 'right-4'}`}>{t.currency}</span>
                    </div>

                    <div className="flex items-center gap-2 bg-blue-50 p-3 rounded-lg text-xs text-blue-800 mb-8 justify-center">
                        <Info size={14} />
                        <p>{t.salaryHint}</p>
                    </div>

                    <button 
                        onClick={handleNextStep}
                        disabled={salary <= 0}
                        className={`w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all ${salary > 0 ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-lg hover:shadow-xl' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
                    >
                        <span>{t.next}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                    </button>
                 </div>
            </div>
        )}

        {/* --- STEP 2: EXPENSES --- */}
        {step === AppStep.EXPENSES && (
            <div className="animate-fade-in space-y-6">

                {/* Header Action */}
                <div className="flex flex-col md:flex-row justify-between items-center bg-white p-4 rounded-xl shadow-sm border border-gray-200 gap-4">
                    <div>
                        <h2 className="text-xl font-bold text-gray-800">{t.step2}</h2>
                        <p className="text-sm text-gray-500">{t.expensesTitle} ({expenses.length})</p>
                    </div>
                    <button 
                        onClick={handleOpenAddModal}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg shadow-md flex items-center gap-2 font-bold transition-all"
                    >
                        <Plus size={18} />
                        {t.addExpense}
                    </button>
                </div>

                {/* The List */}
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 min-h-[300px]">
                     <ExpenseTable 
                        expenses={expenses} 
                        salary={salary} 
                        onDelete={handleDeleteExpense} 
                        onEdit={handleOpenEditModal}
                        lang={lang}
                     />
                </div>

                {/* Nav Buttons */}
                <div className="flex justify-between mt-8">
                     <button 
                        onClick={handlePrevStep}
                        className="px-6 py-3 rounded-xl text-gray-600 hover:bg-gray-100 font-bold flex items-center gap-2 transition-colors"
                     >
                        {isRtl ? <ArrowRight size={20} /> : <ArrowLeft size={20} />}
                        {t.back}
                     </button>

                     <button 
                        onClick={handleNextStep}
                        className="px-8 py-3 rounded-xl bg-emerald-600 hover:bg-emerald-700 text-white font-bold flex items-center gap-2 shadow-lg transition-all"
                     >
                        <span>{t.finish}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                     </button>
                </div>
            </div>
        )}

        {/* --- STEP 3: DASHBOARD --- */}
        {step === AppStep.DASHBOARD && (
          <div className="animate-fade-in space-y-6">

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Charts Column */}
              <div className="lg:col-span-1 flex flex-col gap-4">
                 <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.expensesTitle}</h3>
                    <FinancialChart metrics={metrics} />
                 </div>

                 <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.target} vs {t.actual}</h3>
                    <TargetVsActualChart salary={salary} metrics={metrics} />
                 </div>
              </div>

              {/* Stats Column */}
              <div className="lg:col-span-2 flex flex-col gap-6">
                 {getAnalysis()}

                 <div className="bg-indigo-900 text-white rounded-xl p-6 shadow-lg flex flex-col justify-center h-full min-h-[140px]">
                    <h4 className="text-indigo-200 text-sm font-medium mb-1">{t.savings}</h4>
                    <div className="text-4xl font-bold mb-2 flex items-baseline gap-2">
                         {metrics.totalSavingsCalculated.toLocaleString()} 
                         <span className="text-lg font-normal text-indigo-300">{t.currency}</span>
                    </div>

                    {metrics.remainingSalary > 0 && (
                       <div className="bg-indigo-800/50 rounded px-3 py-2 text-sm flex items-center gap-2 w-fit mt-2">
                          <span className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></span>
                          {t.remaining}: {metrics.remainingSalary.toLocaleString()}
                       </div>
                    )}
                 </div>

                 <div className="flex gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="flex-1 bg-white border border-gray-200 text-gray-600 py-3 rounded-xl font-bold hover:bg-gray-50 flex justify-center items-center gap-2"
                     >
                        <Edit2 size={16} />
                        {t.edit} {t.step2}
                     </button>
                 </div>
              </div>
            </div>

            {/* Expenses Table (Read Only view or quick edit) */}
            {expenses.length > 0 && (
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 animate-fade-in mt-6">
                 <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50 rounded-t-xl">
                   <h3 className="font-bold text-gray-800">{t.expensesTitle}</h3>
                   <button onClick={() => setStep(AppStep.EXPENSES)} className="text-blue-600 text-xs font-bold hover:underline">
                      {t.edit}
                   </button>
                </div>
                <ExpenseTable 
                  expenses={expenses} 
                  salary={salary} 
                  onDelete={handleDeleteExpense} 
                  onEdit={handleOpenEditModal}
                  lang={lang}
                />
              </div>
            )}
          </div>
        )}

      </main>

      {/* Modal */}
      {isModalOpen && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in"
          onClick={(e) => {
             if (e.target === e.currentTarget) handleCloseModal();
          }}
        >
          <div className="w-full max-w-2xl animate-[fadeIn_0.3s_ease-out]">
            <AddExpenseForm 
              salary={salary} 
              currentTotal={metrics.totalExpenses}
              expenses={expenses}
              onAdd={handleAddExpense}
              editingExpense={editingExpense}
              onUpdate={handleUpdateExpense}
              onCancelEdit={handleCloseModal}
              lang={lang}
            />
          </div>
        </div>
      )}

      {/* Persistent Footer */}
      <footer className="fixed bottom-0 w-full bg-white border-t border-gray-200 py-2 px-4 shadow-[0_-2px_10px_rgba(0,0,0,0.05)] z-40 flex justify-between items-center">
        <div className="flex items-center gap-2 text-xs text-slate-500">
           <span>{t.developedBy}</span>
           <a href="https://www.linkedin.com/in/ahmed-alshareef-innovation" target="_blank" rel="noopener noreferrer">
             <img src="./ashareef_logo.png" alt="Logo" className="h-8 object-contain opacity-80 hover:opacity-100" />
           </a>
        </div>

        {/* Export Button (Visible on Dashboard) */}
        {step === AppStep.DASHBOARD && (
             <button 
             onClick={exportPDF}
             disabled={isExporting}
             className={`bg-slate-800 hover:bg-slate-900 text-white px-4 py-2 rounded-lg shadow-lg flex items-center gap-2 transition-transform hover:scale-105 ${isExporting ? 'opacity-70 cursor-wait' : ''}`}
           >
             {isExporting ? <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div> : <Download size={16} />}
             <span className="font-bold text-xs md:text-sm">{t.exportPDF}</span>
           </button>
        )}
      </footer>

    </div>
  );
}

const Edit2 = ({size}:{size:number}) => <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;

export default App;

import React, { useState, useEffect } from 'react';
import { Expense, ExpenseType, Language } from '../types';
import { EXPENSE_TYPES, SUGGESTED_EXPENSES, SUGGESTED_EXPENSES_EN, EXPENSE_MAPPING, EXPENSE_MAPPING_EN, TRANSLATIONS, EXPENSE_TYPE_LABELS } from '../constants';
import { PlusCircle, Save, X, AlertTriangle } from 'lucide-react';

interface AddExpenseFormProps {
  salary: number;
  currentTotal: number;
  expenses: Expense[];
  onAdd: (expense: Omit<Expense, 'id'>) => boolean; 
  editingExpense?: Expense | null;
  onUpdate: (updatedExpense: Expense) => boolean;
  onCancelEdit: () => void;
  lang: Language;
}

export const AddExpenseForm: React.FC<AddExpenseFormProps> = ({ 
  salary, 
  currentTotal, 
  expenses,
  onAdd, 
  editingExpense,
  onUpdate,
  onCancelEdit,
  lang
}) => {
  const t = TRANSLATIONS[lang];
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [type, setType] = useState<ExpenseType>(ExpenseType.NEED);
  const [notes, setNotes] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [advice, setAdvice] = useState<string | null>(null);

  // Determine which suggestions to show
  const currentSuggestions = lang === 'ar' ? SUGGESTED_EXPENSES : SUGGESTED_EXPENSES_EN;

  useEffect(() => {
    if (editingExpense) {
      setName(editingExpense.name);
      setAmount(editingExpense.amount.toString());
      setType(editingExpense.type);
      setNotes(editingExpense.notes || '');
      setError(null);
      setAdvice(null);
    }
  }, [editingExpense]);

  useEffect(() => {
    if (name) {
       // Check Arabic mapping
       if (lang === 'ar' && EXPENSE_MAPPING[name]) {
          setType(EXPENSE_MAPPING[name]);
       }
       // Check English mapping
       if (lang === 'en' && EXPENSE_MAPPING_EN[name]) {
          setType(EXPENSE_MAPPING_EN[name]);
       }
    }
  }, [name, lang]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numAmount = parseFloat(amount);
    if (!name || isNaN(numAmount) || numAmount <= 0) return;

    const amountDiff = editingExpense ? numAmount - editingExpense.amount : numAmount;
    if (currentTotal + amountDiff > salary) {
      const deficit = (currentTotal + amountDiff) - salary;
      setError(`${t.errorSalaryExceeded} (${deficit.toLocaleString()})`);

      const otherExpenses = expenses.filter(e => editingExpense ? e.id !== editingExpense.id : true);
      const currentWants = otherExpenses.filter(e => e.type === ExpenseType.WANT).reduce((sum, e) => sum + e.amount, 0);
      const wantsPct = (currentWants / salary) * 100;

      const largestWant = otherExpenses
        .filter(e => e.type === ExpenseType.WANT)
        .sort((a, b) => b.amount - a.amount)[0];

      let generatedAdvice = "";

      if (lang === 'ar') {
        if (wantsPct > 30 && largestWant) {
            generatedAdvice = `توصية الخبير: إنفاقك على "الرغبات" مرتفع (${Math.round(wantsPct)}%). جرب تقليل بند "${largestWant.name}".`;
        } else if (largestWant) {
            generatedAdvice = `توصية الخبير: حاول تقليل الكماليات مثل "${largestWant.name}".`;
        } else {
            generatedAdvice = `توصية الخبير: ميزانيتك مضغوطة. راجع مصروفاتك.`;
        }
      } else {
        if (wantsPct > 30 && largestWant) {
            generatedAdvice = `Expert Tip: Your 'Wants' are high (${Math.round(wantsPct)}%). Try reducing "${largestWant.name}".`;
        } else if (largestWant) {
            generatedAdvice = `Expert Tip: Try reducing luxuries like "${largestWant.name}".`;
        } else {
            generatedAdvice = `Expert Tip: Your budget is tight. Review your needs.`;
        }
      }

      setAdvice(generatedAdvice);
      return;
    }

    let success = false;
    if (editingExpense) {
      success = onUpdate({ ...editingExpense, name, amount: numAmount, type, notes });
    } else {
      success = onAdd({ name, amount: numAmount, type, notes });
    }

    if (success) {
      if (!editingExpense) {
        setName('');
        setAmount('');
        setNotes('');
        setType(ExpenseType.NEED);
      }
      setError(null);
      setAdvice(null);
    }
  };

  const handleSuggestionSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (e.target.value) {
      setName(e.target.value);
    }
  };

  const getTypeColorClass = (t: ExpenseType) => {
     switch (t) {
       case ExpenseType.NEED: return 'text-red-700 font-bold';
       case ExpenseType.WANT: return 'text-amber-600 font-bold';
       case ExpenseType.SAVING: return 'text-emerald-600 font-bold';
       default: return 'text-gray-700';
     }
  };

  const isRtl = lang === 'ar';

  return (
    <div className="bg-white p-6 rounded-xl shadow-lg w-full max-w-2xl" dir={isRtl ? 'rtl' : 'ltr'}>
      <div className="flex justify-between items-center mb-6 pb-2 border-b border-gray-100">
        <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
          {editingExpense ? <Edit2Icon /> : <PlusCircleIcon />}
          {editingExpense ? (lang === 'ar' ? 'تعديل المصروف' : 'Edit Expense') : t.addExpense}
        </h3>
        <button 
          onClick={onCancelEdit}
          className="text-gray-400 hover:text-gray-600 p-1 rounded-full hover:bg-gray-100 transition-colors"
        >
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">

          <div className="flex flex-col gap-2">
            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseName}</label>

              <select 
                onChange={handleSuggestionSelect}
                className="w-full mb-2 px-2 py-1.5 text-xs border border-gray-200 bg-gray-50 rounded text-gray-600 focus:border-blue-500 outline-none cursor-pointer"
                defaultValue=""
              >
                <option value="" disabled>{lang === 'ar' ? "↓ اختر من القائمة المقترحة" : "↓ Select suggested expense"}</option>
                {currentSuggestions.map((s, i) => (
                  <option key={i} value={s}>{s}</option>
                ))}
              </select>

              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder={lang === 'ar' ? "أو اكتب الاسم هنا..." : "Expense name..."}
                required
                autoFocus={!editingExpense}
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseAmount}</label>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className={`w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all ${lang==='ar' ? 'mt-[29px]' : 'md:mt-[29px]'}`}
              placeholder="0.00"
              min="0"
              required
            />
          </div>

          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseType}</label>
            <select
              value={type}
              onChange={(e) => setType(e.target.value as ExpenseType)}
              className={`w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none bg-white md:mt-[29px] ${getTypeColorClass(type)}`}
            >
              {EXPENSE_TYPES.map(t => (
                <option key={t} value={t} className={getTypeColorClass(t)}>
                    {EXPENSE_TYPE_LABELS[lang][t]}
                </option>
              ))}
            </select>
          </div>

          <div>
             <label className="block text-xs font-semibold text-gray-500 mb-1">{t.notes}</label>
            <input
              type="text"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all md:mt-[29px]"
              placeholder={lang === 'ar' ? "اختياري" : "Optional"}
            />
          </div>
        </div>

        {error && (
          <div className="bg-red-50 border-r-4 border-red-500 p-4 rounded-md animate-pulse">
            <div className="flex items-start">
              <AlertTriangle className="text-red-500 ltr:mr-2 rtl:ml-2 mt-0.5" size={18} />
              <div>
                <p className="text-sm font-bold text-red-700">{error}</p>
                {advice && <p className="text-sm text-red-600 mt-1 bg-white/50 p-2 rounded">{advice}</p>}
              </div>
            </div>
          </div>
        )}

        <div className="flex justify-end gap-3 pt-4 border-t border-gray-100">
            <button
              type="button"
              onClick={onCancelEdit}
              className="px-6 py-2 rounded-lg border border-gray-300 text-gray-600 hover:bg-gray-50 transition-colors flex items-center gap-2"
            >
              {t.cancel}
            </button>
          <button
            type="submit"
            className="px-6 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700 shadow-md transition-colors flex items-center gap-2"
          >
            {editingExpense ? <Save size={18} /> : <PlusCircle size={18} />}
            {editingExpense ? t.save : t.addExpense}
          </button>
        </div>
      </form>
    </div>
  );
};

const Edit2Icon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;
const PlusCircleIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="16"></line><line x1="8" y1="12" x2="16" y2="12"></line></svg>;

import React from 'react';
import { Trash2, Edit2 } from 'lucide-react';
import { Expense, ExpenseType, Language } from '../types';
import { TRANSLATIONS, EXPENSE_TYPE_LABELS } from '../constants';

interface ExpenseTableProps {
  expenses: Expense[];
  salary: number;
  onDelete: (id: string) => void;
  onEdit: (expense: Expense) => void;
  lang: Language;
}

export const ExpenseTable: React.FC<ExpenseTableProps> = ({ expenses, salary, onDelete, onEdit, lang }) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  const getPercentageColor = (amount: number): string => {
    if (salary === 0) return 'bg-gray-100 text-gray-500';
    const percentage = (amount / salary) * 100;
    if (percentage <= 5) return 'bg-green-100 text-green-800';
    if (percentage <= 15) return 'bg-amber-100 text-amber-800';
    return 'bg-red-100 text-red-800';
  };

  const getTypeBadge = (type: ExpenseType) => {
    const label = EXPENSE_TYPE_LABELS[lang][type];
    switch (type) {
      case ExpenseType.NEED: return <span className="px-2 py-1 rounded-full text-xs bg-red-100 text-red-800 font-medium">{label}</span>;
      case ExpenseType.WANT: return <span className="px-2 py-1 rounded-full text-xs bg-amber-100 text-amber-800 font-medium">{label}</span>;
      case ExpenseType.SAVING: return <span className="px-2 py-1 rounded-full text-xs bg-emerald-100 text-emerald-800 font-medium">{label}</span>;
    }
  };

  return (
    <div className="overflow-x-auto rounded-lg border border-gray-200" dir={isRtl ? 'rtl' : 'ltr'}>
      <table className="w-full text-sm text-right">
        <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
          <tr>
            <th className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{t.expenseName}</th>
            <th className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{t.expenseType}</th>
            <th className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{t.expenseAmount}</th>
            <th className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{t.expenseAmount} %</th>
            <th className={`px-4 py-3 hidden md:table-cell ${isRtl ? 'text-right' : 'text-left'}`}>{t.notes}</th>
            <th className="px-4 py-3 text-center w-24"></th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100 bg-white">
          {expenses.length === 0 ? (
            <tr>
              <td colSpan={6} className="px-4 py-8 text-center text-gray-400">
                {t.noExpenses}
              </td>
            </tr>
          ) : (
            expenses.map((expense) => {
              const percentage = salary > 0 ? Math.ceil((expense.amount / salary) * 100) : 0;
              return (
                <tr key={expense.id} className="hover:bg-gray-50 transition-colors">
                  <td className={`px-4 py-3 font-medium text-gray-900 ${isRtl ? 'text-right' : 'text-left'}`}>{expense.name}</td>
                  <td className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>{getTypeBadge(expense.type)}</td>
                  <td className={`px-4 py-3 font-semibold ${isRtl ? 'text-right' : 'text-left'}`}>{expense.amount.toLocaleString()}</td>
                  <td className={`px-4 py-3 ${isRtl ? 'text-right' : 'text-left'}`}>
                    <span className={`inline-block px-2 py-1 rounded text-xs font-bold ${getPercentageColor(expense.amount)}`}>
                      %{percentage}
                    </span>
                  </td>
                  <td className={`px-4 py-3 text-gray-500 max-w-xs truncate hidden md:table-cell ${isRtl ? 'text-right' : 'text-left'}`}>{expense.notes || '-'}</td>
                  <td className="px-4 py-3">
                    {/* Mobile Optimized Actions: Stacked or Larger touch targets */}
                    <div className="flex items-center justify-center gap-3 md:gap-2">
                      <button 
                        onClick={() => onEdit(expense)} 
                        className="p-2 md:p-1.5 bg-blue-50 text-blue-600 hover:bg-blue-100 rounded-lg transition-colors shadow-sm"
                        title={t.edit}
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => onDelete(expense.id)} 
                        className="p-2 md:p-1.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg transition-colors shadow-sm"
                        title={t.delete}
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })
          )}
        </tbody>
      </table>
    </div>
  );
};

