        <button 
          onClick={onFinish}
          className="text-xs bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1"
        >
          {t.skipToExpenses}
          {isRtl ? <ArrowLeft size={14} /> : <ArrowRight size={14} />}
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm flex flex-col gap-2 ${
                msg.sender === 'user' 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : (msg.isError ? 'bg-red-50 text-red-800 border border-red-100' : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none')
              }`}
            >
               <div className="flex items-start gap-2">
                   {msg.isError && <AlertTriangle size={16} className="mt-0.5 shrink-0" />}
                   <span>{msg.text}</span>
               </div>

               {/* Show Update Key Button if Auth Error */}
               {msg.isAuthError && (window as any).aistudio && (
                   <button 
                     onClick={handleUpdateKey}
                     className="mt-2 bg-red-100 hover:bg-red-200 text-red-800 text-xs font-bold py-2 px-3 rounded-lg flex items-center gap-2 w-fit transition-colors"
                   >
                       <Key size={14} />
                       {lang === 'ar' ? "تحديث مفتاح API" : "Update API Key"}
                   </button>
               )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-gray-200 text-gray-500 px-4 py-2 rounded-full text-xs rounded-bl-none">
              ...
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-white border-t border-gray-100">
        <div className="flex gap-2 relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={t.chatPlaceholder}
            className="flex-1 bg-gray-100 text-gray-800 placeholder-gray-400 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all outline-none disabled:bg-gray-50"
            autoFocus
            disabled={messages.length > 0 && !!messages[messages.length - 1].isAuthError}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isTyping || (messages.length > 0 && !!messages[messages.length - 1].isAuthError)}
            className={`p-3 rounded-xl transition-all shadow-md ${
              !input.trim() || isTyping || (messages.length > 0 && !!messages[messages.length - 1].isAuthError)
               ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
               : 'bg-blue-600 text-white hover:bg-blue-700 hover:scale-105 active:scale-95'
            }`}
          >
            <Send size={20} className={isRtl ? 'rotate-180' : ''} />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { Send, Bot, User, ArrowRight, ArrowLeft, AlertTriangle, Key, CheckCircle2 } from 'lucide-react';
import { Expense, ExpenseType, Language, BudgetRule } from '../types';
import { TRANSLATIONS } from '../constants';

interface FinancialAdvisorProps {
  salary: number;
  onAddExpense: (expense: Omit<Expense, 'id'>) => void;
  onUpdateRule: (rule: BudgetRule) => void;
  onFinish: () => void;
  lang: Language;
}

interface Message {
  id: string;
  sender: 'ai' | 'user';
  text: string;
  isError?: boolean;
  isAuthError?: boolean;
}

interface QuickReply {
  label: string;
  value: string;
}

export const FinancialAdvisor: React.FC<FinancialAdvisorProps> = ({ 
  salary, 
  onAddExpense, 
  onUpdateRule,
  onFinish, 
  lang 
}) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [quickReplies, setQuickReplies] = useState<QuickReply[]>([]);
  const [isFinished, setIsFinished] = useState(false);
  const [retryTrigger, setRetryTrigger] = useState(0);

  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, quickReplies]);

  useEffect(() => {
    const initChat = async () => {
      setMessages([]);
      setQuickReplies([]);
      setIsFinished(false);

      if (!process.env.API_KEY) {
         setMessages([{
             id: 'error-missing',
             sender: 'ai',
             text: lang === 'ar' 
               ? "مفتاح API غير متوفر. يرجى تحديد مفتاح صالح." 
               : "API Key is missing. Please select a valid key.",
             isError: true,
             isAuthError: true
         }]);
         return;
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Detailed Prompt to force JSON structure and Step-by-Step logic
        const systemInstruction = `
          You are 'Qawam Assistant', an expert financial planner.
          Current User Context:
          - Salary: ${salary} ${t.currency}
          - Language: ${lang === 'ar' ? 'Arabic' : 'English'}

          OBJECTIVE:
          Conduct a structured interview to determine the user's financial profile, then recommend a customized 50/30/20 rule and estimate expenses.

          LOGIC FOR RULE ADJUSTMENT:
          - Standard: 50% Needs, 30% Wants, 20% Savings.
          - High Cost of Living (Rent + Low Salary): Increase Needs (e.g., 60/20/20 or 60/30/10).
          - High Family Obligations (Many kids): Increase Needs.
          - High Salary (> 20k) + Low Obligations: Increase Savings (e.g., 40/30/30).

          INTERVIEW FLOW:
          1. Ask Marital Status. Options: [Single, Married].
          2. Ask Family Size (if Married). Options: [No kids, 1-2 kids, 3+ kids].
          3. Ask Housing Status. Options: [Rent, Owned, With Family].
          4. Ask about Debt/Loans. Options: [None, Car Loan, Personal Loan, Both].
          5. Finalize: Analyze all inputs + Salary. Output the rule and suggested expenses.

          OUTPUT FORMAT:
          You must ALWAYS return a raw JSON object (no markdown formatting).

          Structure for Questions (Phases 1-4):
          {
            "message": "The question text here...",
            "options": ["Option A", "Option B", "Option C"]
          }

          Structure for Final Result (Phase 5):
          {
            "message": "Conclusion message explaining the rule choice...",
            "isFinal": true,
            "rule": { "needs": 50, "wants": 30, "savings": 20 },
            "expenses": [
              { "name": "Rent", "amount": 4000, "type": "احتياج" },
              { "name": "Grocery", "amount": 1500, "type": "احتياج" }
            ]
          }

          Note on Expenses:
          Based on the answers (e.g., if Rent -> add Rent expense. If Car Loan -> add Loan expense). Estimate amounts based on typical ratios for the given Salary (e.g., Rent is usually 25-30% of salary).
          Expense Types: 'احتياج' (Need), 'رغبة' (Want), 'ادخار واستثمار' (Savings).
        `;

        const chat = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            systemInstruction: systemInstruction,
            temperature: 0.5, // Lower temperature for more deterministic flow
          },
        });

        chatSessionRef.current = chat;

        // Start the conversation
        setIsTyping(true);
        // We send an empty prompt or a hidden "start" prompt to trigger the first question
        const response = await chat.sendMessage({ message: "Start the interview." });
        processResponse(response);

      } catch (error) {
        console.error("Failed to init chat", error);
        setMessages([{
             id: 'init-error',
             sender: 'ai',
             text: lang === 'ar' ? "فشل تهيئة المحادثة." : "Failed to initialize chat.",
             isError: true
        }]);
        setIsTyping(false);
      }
    };

    initChat();
  }, [salary, lang, t.currency, retryTrigger]);

  const processResponse = (response: GenerateContentResponse) => {
    setIsTyping(false);
    const rawText = response.text || "";

    try {
      // Clean up markdown code blocks if present to get raw JSON
      const jsonStr = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
      const data = JSON.parse(jsonStr);

      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        sender: 'ai', 
        text: data.message 
      }]);

      if (data.isFinal) {
        setQuickReplies([]);
        setIsFinished(true);

        // Apply logic
        if (data.rule) onUpdateRule(data.rule);
        if (data.expenses && Array.isArray(data.expenses)) {
             data.expenses.forEach((exp: any) => {
              let type: ExpenseType = ExpenseType.NEED;
              // Map text types to Enum
              if (exp.type === 'رغبة' || exp.type === 'Wants') type = ExpenseType.WANT;
              if (exp.type === 'ادخار واستثمار' || exp.type === 'Savings') type = ExpenseType.SAVING;

              onAddExpense({
                name: exp.name,
                amount: typeof exp.amount === 'number' ? exp.amount : parseFloat(exp.amount),
                type: type,
                notes: 'AI Suggested'
              });
            });
        }
      } else if (data.options && Array.isArray(data.options)) {
        setQuickReplies(data.options.map((opt: string) => ({ label: opt, value: opt })));
      }

    } catch (e) {
      console.error("JSON Parse Error", e, rawText);
      // Fallback if AI breaks character
      setMessages(prev => [...prev, { id: Date.now().toString(), sender: 'ai', text: rawText }]);
    }
  };

  const handleSend = async (text: string) => {
    if (!text.trim() || !chatSessionRef.current) return;

    // Add user message
    const userMsg: Message = { id: Date.now().toString(), sender: 'user', text: text };
    setMessages(prev => [...prev, userMsg]);
    setQuickReplies([]); // Clear options
    setInput('');
    setIsTyping(true);

    try {
      const response = await chatSessionRef.current.sendMessage({ message: text });
      processResponse(response);
    } catch (error: any) {
      console.error("Chat Error:", error);
      setIsTyping(false);

      // Error Handling similar to previous implementation
      let errorMsg = lang === 'ar' ? "عذراً، حدث خطأ في الاتصال." : "Sorry, connection error.";
      let isAuthError = false;
      let detailedMsg = error.message || "";

      if (typeof detailedMsg === 'string' && detailedMsg.includes('{')) {
          try {
             const jsonPart = detailedMsg.substring(detailedMsg.indexOf('{'));
             const errObj = JSON.parse(jsonPart);
             if (errObj.error && errObj.error.message) detailedMsg = errObj.error.message;
          } catch (e) { /* ignore */ }
      }

      if (detailedMsg.includes("API key not valid") || detailedMsg.includes("API_KEY_INVALID")) {
          errorMsg = lang === 'ar' ? "مفتاح API غير صالح." : "Invalid API Key.";
          isAuthError = true;
      }

      setMessages(prev => [...prev, { 
          id: Date.now().toString(), 
          sender: 'ai', 
          text: errorMsg,
          isError: true,
          isAuthError: isAuthError 
      }]);
    }
  };

  const handleUpdateKey = async () => {
      const win = window as any;
      if (win.aistudio) {
          try {
              await win.aistudio.openSelectKey();
              setMessages([]);
              setRetryTrigger(prev => prev + 1); 
          } catch(e) { console.error(e); }
      }
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden animate-fade-in relative">
      {/* Header */}
      <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-4 text-white flex justify-between items-center shadow-md z-10">
        <div className="flex items-center gap-3">
          <div className="bg-white/20 p-2 rounded-full">
            <Bot size={24} />
          </div>
          <div>
            <h3 className="font-bold text-lg">{t.advisorStep}</h3>
            <p className="text-xs text-blue-100 opacity-80">Gemini AI Powered</p>
          </div>
        </div>
        <button 
          onClick={onFinish}
          className="text-xs bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1"
        >
          {t.skipToExpenses}
          {isRtl ? <ArrowLeft size={14} /> : <ArrowRight size={14} />}
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm flex flex-col gap-2 ${
                msg.sender === 'user' 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : (msg.isError ? 'bg-red-50 text-red-800 border border-red-100' : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none')
              }`}
            >
               <div className="flex items-start gap-2">
                   {msg.isError && <AlertTriangle size={16} className="mt-0.5 shrink-0" />}
                   <span className="whitespace-pre-wrap">{msg.text}</span>
               </div>
               {msg.isAuthError && (window as any).aistudio && (
                   <button onClick={handleUpdateKey} className="mt-2 bg-red-100 text-red-800 text-xs font-bold py-2 px-3 rounded-lg flex items-center gap-2 w-fit">
                       <Key size={14} /> {lang === 'ar' ? "تحديث المفتاح" : "Update Key"}
                   </button>
               )}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-gray-200 text-gray-500 px-4 py-2 rounded-full text-xs rounded-bl-none">
              Thinking...
            </div>
          </div>
        )}

        {/* Quick Replies / Chips */}
        {quickReplies.length > 0 && !isTyping && (
          <div className="flex flex-wrap gap-2 mt-2 animate-fade-in">
            {quickReplies.map((reply, idx) => (
              <button
                key={idx}
                onClick={() => handleSend(reply.value)}
                className="bg-white border border-blue-200 text-blue-700 hover:bg-blue-50 px-4 py-2 rounded-full text-sm font-medium transition-all shadow-sm hover:scale-105 active:scale-95"
              >
                {reply.label}
              </button>
            ))}
          </div>
        )}

        {isFinished && (
           <div className="flex justify-center mt-4 pb-4 animate-fade-in">
              <button
                onClick={onFinish}
                className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-bold shadow-lg hover:bg-emerald-700 hover:scale-105 transition-all flex items-center gap-2"
              >
                <CheckCircle2 size={20} />
                {lang === 'ar' ? "اعتماد الخطة والمتابعة" : "Approve Plan & Continue"}
              </button>
           </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area (Still allow manual typing if user wants specific details) */}
      {!isFinished && (
        <div className="p-4 bg-white border-t border-gray-100">
          <div className="flex gap-2 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend(input)}
              placeholder={t.chatPlaceholder}
              disabled={isTyping || quickReplies.length > 0} // Optional: Disable typing if chips are present to force flow, or keep enabled for flexibility.
              className="flex-1 bg-gray-100 text-gray-800 placeholder-gray-400 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all outline-none disabled:bg-gray-50 disabled:cursor-not-allowed"
            />
            <button 
              onClick={() => handleSend(input)}
              disabled={!input.trim() || isTyping}
              className={`p-3 rounded-xl transition-all shadow-md ${
                !input.trim() || isTyping 
                ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                : 'bg-blue-600 text-white hover:bg-blue-700 hover:scale-105 active:scale-95'
              }`}
            >
              <Send size={20} className={isRtl ? 'rotate-180' : ''} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

