export const FinancialAdvisor: React.FC<FinancialAdvisorProps> = ({ 
  salary, 
  onAddExpense, 
  onUpdateRule,
  onFinish, 
  lang 
}) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [quickReplies, setQuickReplies] = useState<QuickReply[]>([]);
  const [isFinished, setIsFinished] = useState(false);
  const [retryTrigger, setRetryTrigger] = useState(0);

  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, quickReplies]);

  useEffect(() => {
    const initChat = async () => {
      setMessages([]);
      setQuickReplies([]);
      setIsFinished(false);

      if (!process.env.API_KEY) {
         setMessages([{
             id: 'error-missing',
             sender: 'ai',
             text: lang === 'ar' 
               ? "مفتاح API غير متوفر. يرجى تحديد مفتاح صالح." 
               : "API Key is missing. Please select a valid key.",
             isError: true,
             isAuthError: true
         }]);
         return;
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // The detailed prompt for the Financial Consultant Persona
        const systemInstruction = `
          أنت "المستشار المالي" (Financial Consultant) لتطبيق "قوام".
          سياق المستخدم الحالي:
          - الراتب المدخل: ${salary} ${t.currency}
          - اللغة: ${lang === 'ar' ? 'Arabic' : 'English'}

          الدور والهدف:
          أنت مستشار مالي شخصي متخصص في التخطيط الشهري وإدارة التدفقات النقدية. هدفك هو بناء خطة شهرية تفصيلية واختيار القاعدة المالية الأنسب (مثلاً 50/30/20 أو 60/20/20) بناءً على الواقع الفعلي للمستخدم.

          المبادئ الثابتة:
          1. لا تقدم نصائح استثمارية ملزمة.
          2. قراراتك مبنية على الأرقام. إذا كانت البيانات ناقصة، اسأل عنها.
          3. ميز بوضوح بين المصروفات الثابتة، المتغيرة، والدورية.
          4. تعامل مع المستخدم كشريك؛ اشرح لماذا اخترت القاعدة المالية.

          بروتوكول جمع البيانات (مراحل الاستجواب):
          لا تسأل كل الأسئلة دفعة واحدة. قم بقيادة المحادثة خطوة بخطوة (سؤال واحد أو سؤالين في كل مرة):

          المرحلة 1: تدقيق الدخل
          - تأكد هل الراتب (${salary}) ثابت أم متغير؟ وتواريخ الاستحقاق. وهل يوجد دخل إضافي؟

          المرحلة 2: الالتزامات الثابتة
          - اسأل عن الإيجار/السكن، أقساط القروض، الفواتير الثابتة، تعليم، تحويلات عائلية. (اطلب المبالغ).

          المرحلة 3: المصروفات المتغيرة (نمط الحياة)
          - اسأل عن متوسط الصرف على: الأكل، المواصلات، الترفيه، المشتريات الشخصية.

          المرحلة 4: الديون والمدخرات
          - تفاصيل الديون (إن وجدت ولم تذكر سابقاً).
          - هل يوجد صندوق طوارئ؟ ما هي الأهداف المالية؟

          المرحلة 5: التحليل والتوصية (النهاية)
          - قم بتحليل العجز/الفائض.
          - اختر القاعدة المالية الأنسب (مثلاً: إذا الديون عالية، اقترح خطة سداد ديون بقاعدة 50/15/35).
          - اعرض ملخصاً سريعاً.

          CRITICAL OUTPUT FORMAT (JSON CONTROL):
          في كل رد، يجب أن ترسل كائن JSON فقط (بدون ماركداون).

          Structure during conversation (Phases 1-4):
