        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      {!isFinished && (
        <div className="p-4 bg-white border-t border-gray-100">
          <div className="flex gap-2 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend(input)}
              placeholder={t.chatPlaceholder}
              disabled={isTyping || quickReplies.length > 0} 
              className="flex-1 bg-gray-100 text-gray-800 placeholder-gray-400 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all outline-none disabled:bg-gray-50 disabled:cursor-not-allowed"
            />
            <button 
              onClick={() => handleSend(input)}
              disabled={!input.trim() || isTyping}
              className={`p-3 rounded-xl transition-all shadow-md ${
                !input.trim() || isTyping 
                ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:scale-105 active:scale-95'
              }`}
            >
              <Send size={20} className={isRtl ? 'rotate-180' : ''} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { Send, Bot, ArrowRight, ArrowLeft, AlertTriangle, Key, CheckCircle2 } from 'lucide-react';
import { Expense, ExpenseType, Language, BudgetRule } from '../types';
import { TRANSLATIONS, EXPENSE_MAPPING, EXPENSE_MAPPING_EN } from '../constants';

interface FinancialAdvisorProps {
  salary: number;
  onAddExpense: (expense: Omit<Expense, 'id'>) => void;
  onUpdateRule: (rule: BudgetRule) => void;
  onFinish: () => void;
  lang: Language;
}

interface Message {
  id: string;
  sender: 'ai' | 'user';
  text: string;
  isError?: boolean;
  isAuthError?: boolean;
}

interface QuickReply {
  label: string;
  value: string;
}

export const FinancialAdvisor: React.FC<FinancialAdvisorProps> = ({ 
  salary, 
  onAddExpense, 
  onUpdateRule, 
  onFinish, 
  lang 
}) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [quickReplies, setQuickReplies] = useState<QuickReply[]>([]);
  const [isFinished, setIsFinished] = useState(false);
  const [retryTrigger, setRetryTrigger] = useState(0);

  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, quickReplies]);

  useEffect(() => {
    const initChat = async () => {
      setMessages([]);
      setQuickReplies([]);
      setIsFinished(false);

      if (!process.env.API_KEY) {
         setMessages([{
             id: 'error-missing',
             sender: 'ai',
             text: lang === 'ar' 
               ? "مفتاح API غير متوفر. يرجى تحديد مفتاح صالح." 
               : "API Key is missing. Please select a valid key.",
             isError: true,
             isAuthError: true
         }]);
         return;
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Updated Prompt: "Qawam Advisor", strict single item, exact amounts only
        const systemInstruction = `
          Context: User Salary = ${salary} ${t.currency}. Language: ${lang === 'ar' ? 'Arabic' : 'English'}.

          ROLE:
          You are "Qawam's Financial Advisor" (المستشار المالي من قوام) 🤖. 
          Style: Professional, Systematic, Friendly.

          **CORE RULES:**
          1. **ONE ITEM AT A TIME**: Never group expenses. Ask for Electricity separate from Water, separate from Internet.
          2. **STRICT FLOW**: 
             - Question 1: "Do you have [Expense Name]?" -> Options: ["Yes ✅", "No ❌"].
             - If User says "Yes" -> Question 2: "How much exactly is the monthly cost?" -> Options: [] (User MUST type amount).
             - If User says "No" -> Move to next item immediately.
          3. **NO RANGES**: Never offer price ranges (e.g., 500-1000). Financial planning requires exact numbers.

          **INTERVIEW SCRIPT (Follow strictly):**

          1. **Housing (Rent/Mortgage)** 🏠
             - Q: "Do you pay monthly Rent or Mortgage?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "Please enter the exact monthly amount."

          2. **Electricity Bill** ⚡
             - Q: "Do you pay an Electricity bill?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "What is the average monthly bill amount?"

          3. **Water Bill** 💧
             - Q: "Do you pay a Water bill?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "What is the average monthly bill amount?"

          4. **Car Loan** 🚗
             - Q: "Do you have a Car Loan installment?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "What is the exact monthly installment?"

          5. **Fuel & Transport** ⛽
             - Q: "Do you have monthly Fuel or Transportation costs?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "How much do you spend exactly per month?"

          6. **Personal Loan** 💳
             - Q: "Do you have a Personal Bank Loan?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "What is the monthly payment?"

          7. **Groceries** 🛒
             - Q: "Do you pay for Groceries?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "What is the exact monthly cost?"

          8. **Mobile/Telecom** 📱
             - Q: "Do you pay for Mobile or Internet?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "How much is the total monthly bill?"

          9. **Restaurants & Cafes** ☕
             - Q: "Do you have a budget for Restaurants and Cafes?"
             - Opt: ["Yes ✅", "No ❌"]
             - If Yes -> Q: "How much do you allocate for this?"

          10. **Family/Housemaid** 👨‍👩‍👧‍👦
              - Q: "Do you pay for a Housemaid or Family Support?"
              - Opt: ["Yes ✅", "No ❌"]
              - If Yes -> Q: "How much is the monthly amount?"

          **FINISH & ANALYSIS** 🏁
             - Sum all confirmed expenses.
             - Calculate Needs % (Rent + Loans + Bills + Groceries + Fuel).
             - Decide Rule:
               - Needs > 60% -> Suggest 70/20/10.
               - Needs 45-60% -> Suggest 60/20/20.
               - Needs < 45% -> Suggest 50/30/20.
             - Output FINAL JSON.

          OUTPUT FORMAT (JSON ONLY):
          {
            "message": "Question text...",
            "options": ["Yes ✅", "No ❌"] (OR empty array [] if asking for amount)
          }

          Final JSON Format:
          {
            "message": "Final analysis text...",
            "isFinal": true,
            "rule": { "needs": 60, "wants": 20, "savings": 20 },
            "expenses": [ 
               { "name": "Rent 🏠", "amount": 3000, "type": "احتياج" },
               ...
            ]
          }
        `;

        const chat = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            systemInstruction: systemInstruction,
            temperature: 0.1, // Very low temperature for strict script adherence
          },
        });

        chatSessionRef.current = chat;

        setIsTyping(true);
        // Trigger the start
        const response = await chat.sendMessage({ message: "Start the interview script step 1." });
        processResponse(response);

      } catch (error) {
        console.error("Failed to init chat", error);
        setMessages([{
             id: 'init-error',
             sender: 'ai',
             text: lang === 'ar' ? "فشل تهيئة المستشار المالي." : "Failed to initialize Financial Consultant.",
             isError: true
        }]);
        setIsTyping(false);
      }
    };

    initChat();
  }, [salary, lang, t.currency, retryTrigger]);

  const processResponse = (response: GenerateContentResponse) => {
    setIsTyping(false);
    const rawText = response.text || "";

    try {
      const jsonStr = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
      const data = JSON.parse(jsonStr);

      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        sender: 'ai', 
        text: data.message 
      }]);

      if (data.isFinal) {
        setQuickReplies([]);
        setIsFinished(true);

        if (data.rule) onUpdateRule(data.rule);
        if (data.expenses && Array.isArray(data.expenses)) {
             data.expenses.forEach((exp: any) => {
              let type: ExpenseType = ExpenseType.NEED;
              if (exp.type === 'رغبة' || exp.type === 'Wants' || exp.type === 'Want') type = ExpenseType.WANT;
              if (exp.type === 'ادخار واستثمار' || exp.type === 'Savings' || exp.type === 'Saving') type = ExpenseType.SAVING;
              if (exp.type === 'احتياج' || exp.type === 'Needs' || exp.type === 'Need') type = ExpenseType.NEED;

              onAddExpense({
                name: exp.name,
                amount: typeof exp.amount === 'number' ? exp.amount : parseFloat(exp.amount),
                type: type,
                notes: 'AI Auditor Plan 🤖'
              });
            });
        }
      } else if (data.options && Array.isArray(data.options)) {
        setQuickReplies(data.options.map((opt: string) => ({ label: opt, value: opt })));
      } else {
        setQuickReplies([]); // Clear options if none provided (e.g. asking for amount)
      }

    } catch (e) {
      console.error("JSON Parse Error", e, rawText);
      setMessages(prev => [...prev, { id: Date.now().toString(), sender: 'ai', text: rawText }]);
    }
  };

  const handleSend = async (text: string) => {
    if (!text.trim() || !chatSessionRef.current) return;

    const userMsg: Message = { id: Date.now().toString(), sender: 'user', text: text };
    setMessages(prev => [...prev, userMsg]);
    setQuickReplies([]);
    setInput('');
    setIsTyping(true);

    try {
      const response = await chatSessionRef.current.sendMessage({ message: text });
      processResponse(response);
    } catch (error: any) {
      console.error("Chat Error:", error);
      setIsTyping(false);

      let errorMsg = lang === 'ar' ? "عذراً، حدث خطأ في الاتصال." : "Sorry, connection error.";
      let isAuthError = false;
      let detailedMsg = error.message || "";

      if (typeof detailedMsg === 'string' && detailedMsg.includes('{')) {
          try {
             const jsonPart = detailedMsg.substring(detailedMsg.indexOf('{'));
             const errObj = JSON.parse(jsonPart);
             if (errObj.error && errObj.error.message) detailedMsg = errObj.error.message;
          } catch (e) { /* ignore */ }
      }

      if (detailedMsg.includes("API key not valid") || detailedMsg.includes("API_KEY_INVALID")) {
          errorMsg = lang === 'ar' ? "مفتاح API غير صالح." : "Invalid API Key.";
          isAuthError = true;
      }

      setMessages(prev => [...prev, { 
          id: Date.now().toString(), 
          sender: 'ai', 
          text: errorMsg,
          isError: true,
          isAuthError: isAuthError 
      }]);
    }
  };

  const handleUpdateKey = async () => {
      const win = window as any;
      if (win.aistudio) {
          try {
              await win.aistudio.openSelectKey();
              setMessages([]);
              setRetryTrigger(prev => prev + 1); 
          } catch(e) { console.error(e); }
      }
  };

  return (
    <div className="flex flex-col h-[650px] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden animate-fade-in relative">
      {/* Header */}
      <div className="bg-gradient-to-r from-indigo-600 to-violet-600 p-4 text-white flex justify-between items-center shadow-md z-10">
        <div className="flex items-center gap-3">
          <div className="bg-white/20 p-2 rounded-full">
            <Bot size={24} />
          </div>
          <div>
            <h3 className="font-bold text-lg">{t.advisorStep}</h3>
            <p className="text-xs text-indigo-100 opacity-90">AI Auditor Mode 🤖</p>
          </div>
        </div>
        <button 
          onClick={onFinish}
          className="text-xs bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1"
        >
          {t.skipToExpenses}
          {isRtl ? <ArrowLeft size={14} /> : <ArrowRight size={14} />}
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm flex flex-col gap-2 ${
                msg.sender === 'user' 
                  ? 'bg-indigo-600 text-white rounded-br-none' 
                  : (msg.isError ? 'bg-red-50 text-red-800 border border-red-100' : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none')
              }`}
            >
               <div className="flex items-start gap-2">
                   {msg.isError && <AlertTriangle size={16} className="mt-0.5 shrink-0" />}
                   <span className="whitespace-pre-wrap">{msg.text}</span>
               </div>
               {msg.isAuthError && (window as any).aistudio && (
                   <button onClick={handleUpdateKey} className="mt-2 bg-red-100 text-red-800 text-xs font-bold py-2 px-3 rounded-lg flex items-center gap-2 w-fit">
                       <Key size={14} /> {lang === 'ar' ? "تحديث المفتاح" : "Update Key"}
                   </button>
               )}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-gray-200 text-gray-500 px-4 py-2 rounded-full text-xs rounded-bl-none">
              جاري التفكير 🤔...
            </div>
          </div>
        )}

        {/* Quick Replies / Chips */}
        {quickReplies.length > 0 && !isTyping && (
          <div className="flex flex-wrap gap-2 mt-2 animate-fade-in">
            {quickReplies.map((reply, idx) => (
              <button
                key={idx}
                onClick={() => handleSend(reply.value)}
                className="bg-white border border-indigo-200 text-indigo-700 hover:bg-indigo-50 px-4 py-2 rounded-full text-sm font-medium transition-all shadow-sm hover:scale-105 active:scale-95"
              >
                {reply.label}
              </button>
            ))}
          </div>
        )}

        {isFinished && (
           <div className="flex justify-center mt-4 pb-4 animate-fade-in">
              <button
                onClick={onFinish}
                className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-bold shadow-lg hover:bg-emerald-700 hover:scale-105 transition-all flex items-center gap-2"
              >
                <CheckCircle2 size={20} />
                {lang === 'ar' ? "اعتماد الخطة والمتابعة" : "Approve Plan & Continue"}
              </button>
           </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      {!isFinished && (
        <div className="p-4 bg-white border-t border-gray-100">
          <div className="flex gap-2 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend(input)}
              placeholder={t.chatPlaceholder}
              disabled={isTyping || quickReplies.length > 0} 
              className="flex-1 bg-gray-100 text-gray-800 placeholder-gray-400 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all outline-none disabled:bg-gray-50 disabled:cursor-not-allowed"
            />
            <button 
              onClick={() => handleSend(input)}
              disabled={!input.trim() || isTyping}
              className={`p-3 rounded-xl transition-all shadow-md ${
                !input.trim() || isTyping 
                ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:scale-105 active:scale-95'
              }`}
            >
              <Send size={20} className={isRtl ? 'rotate-180' : ''} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

